var doubaoApiBase = 'https://api.sway99.com/api/app/api/doubao_tts';
var doubaoApiKey = '8c97b4c7-4ecb-5dc2-3d9b-5987571224c2';
var speakerMap = {
    '桃子女声': 'taozi',
    '爽快女声': 'shuangkuai',
    '甜美女声': 'tianmei',
    '清澈女声': 'qingche',
    '阳光男声': 'male',
    '沉稳男声': 'chenwen',
    '英文女声': 'en_female'
};
function doubaoTTS(text, speed) {
    var info = this.source.getLoginInfoMap();
    var speaker = info.get('音色') || '桃子女声';
    var speakerId = speakerMap[speaker] || 'taozi';
    var apiSpeed = Math.max(-100, Math.min(100, (speed - 5) * 20));
    var pitch = info.get('音调') || '0';
    var url = doubaoApiBase + '?action=synthesize' +
        '&text=' + encodeURIComponent(text) +
        '&speaker=' + speakerId +
        '&speed=' + apiSpeed +
        '&pitch=' + pitch +
        '&api_key=' + doubaoApiKey;
    var response = java.ajax(url);
    var json = JSON.parse(response);
    if (json.code === 0 && json.data && json.data.audio_url) {
        return json.data.audio_url;
    } else {
        throw new Error(json.msg || 'TTS合成失败');
    }
}

